SELECT
FROM tb_csm_semotong_review r LEFT JOIN tb_pmb_plan_list p ON r.plan_id = p.id LEFT JOIN tb_mbm_user b ON r.create_id = b.id LEFT JOIN tb_mbm_admin_user c ON r.modified_id = c.id
ORDER BY r.create_date DESC LIMIT #{offset}, #{recordSize}

mapper.update:
UPDATE tb_csm_semotong_review 
SET
	 manage_memo    =#{manageMemo}
	,display_yn    =#{displayYn}
	,modified_date  = now()
	,modified_id    =#{modifiedId}
WHERE id = #{id}

UPDATE tb_csm_semotong_review 
SET	   display_yn    = #{displayYn}
WHERE  id            = #{id}
